def plot_perclass_weighting_comparison(save_path: str = "static/baseline") -> None:
    """Compare per-class accuracy between balanced and unweighted models."""
    # Compare k5_avg and k7_avg (both show interesting weighting effects)
    configs = [
        (
            "SimpleCNN_k5_avg_balanced",
            "SimpleCNN_k5_avg_unweighted",
            "k=5, Avg Pooling",
        ),
        (
            "SimpleCNN_k7_avg_balanced",
            "SimpleCNN_k7_avg_unweighted",
            "k=7, Avg Pooling",
        ),
    ]

    fig = plt.figure(figsize=(16, 6))
    gs = GridSpec(1, 2, figure=fig, wspace=0.3)

    for idx, (balanced_name, unweighted_name, title) in enumerate(configs):
        ax = fig.add_subplot(gs[0, idx])

        # Load confusion matrices
        cm_balanced = load_confusion_matrix(balanced_name)
        cm_unweighted = load_confusion_matrix(unweighted_name)

        # Calculate per-class accuracy
        num_classes = cm_balanced.shape[0]
        acc_balanced = []
        acc_unweighted = []
        class_support = []

        for i in range(num_classes):
            total = cm_balanced[i].sum()
            if total > 0:
                acc_balanced.append(cm_balanced[i, i] / total * 100)
                acc_unweighted.append(cm_unweighted[i, i] / total * 100)
                class_support.append(total)
            else:
                acc_balanced.append(0)
                acc_unweighted.append(0)
                class_support.append(0)

        acc_balanced = np.array(acc_balanced)
        acc_unweighted = np.array(acc_unweighted)
        class_support = np.array(class_support)

        # Calculate improvement/degradation
        improvement = acc_balanced - acc_unweighted

        # Create scatter plot colored by improvement
        x = np.arange(num_classes)
        colors = ["#e74c3c" if imp > 0 else "#3498db" for imp in improvement]

        # Plot bars
        for i in range(num_classes):
            ax.bar(
                x[i] - 0.2,
                acc_balanced[i],
                width=0.35,
                color="#e74c3c",
                alpha=0.7,
                label="Balanced" if i == 0 else "",
            )
            ax.bar(
                x[i] + 0.2,
                acc_unweighted[i],
                width=0.35,
                color="#3498db",
                alpha=0.7,
                label="Unweighted" if i == 0 else "",
            )

        ax.set_xlabel("Digit Sum (Class)", fontsize=11, fontweight="bold")
        ax.set_ylabel("Per-Class Accuracy (%)", fontsize=11, fontweight="bold")
        ax.set_title(title, fontsize=12, fontweight="bold")
        ax.set_xticks(x[::3])  # Show every 3rd class label to avoid crowding
        ax.set_xticklabels(x[::3])
        ax.legend(fontsize=9)
        ax.grid(axis="y", alpha=0.3)
        ax.set_ylim([0, 105])

    plt.suptitle(
        "Per-Class Accuracy: Balanced vs Unweighted",
        fontsize=14,
        fontweight="bold",
        y=1.02,
    )

    # Save figure
    os.makedirs(save_path, exist_ok=True)
    output_path = Path(save_path) / "perclass_weighting_comparison.png"
    plt.savefig(output_path, dpi=300, bbox_inches="tight")
    print(f"Saved: {output_path}")
    plt.close()


def plot_class_distribution(save_path: str = "static/baseline") -> None:
    """Plot the class distribution (digit sum distribution) in the training set."""
    # Load from training data directly
    from pathlib import Path

    train_labels = np.load(Path("data/processed/train/labels.npy"))
    unique_labels, class_counts = np.unique(train_labels, return_counts=True)

    fig, ax = plt.subplots(figsize=(12, 5))

    x = np.arange(len(class_counts))
    bars = ax.bar(x, class_counts, color="#2c3e50", alpha=0.8)

    # Highlight extreme classes (rare)
    for i in [0, 1, 2, 35, 36]:
        if i < len(bars):
            bars[i].set_color("#e74c3c")
            bars[i].set_alpha(0.8)

    ax.set_xlabel("Digit Sum (Class)", fontsize=12, fontweight="bold")
    ax.set_ylabel("Number of Samples", fontsize=12, fontweight="bold")
    ax.set_title("Class Distribution in Training Set", fontsize=13, fontweight="bold")
    ax.set_xticks(x[::3])  # Show every 3rd label
    ax.set_xticklabels(x[::3])
    ax.grid(axis="y", alpha=0.3)

    # Add text annotation
    total = class_counts.sum()
    rare_classes = [0, 1, 2, 35, 36]
    rare_count = sum(class_counts[i] for i in rare_classes if i < len(class_counts))
    rare_pct = (rare_count / total) * 100
    ax.text(
        0.98,
        0.97,
        f"Rare classes (red): {rare_pct:.1f}% of data",
        transform=ax.transAxes,
        ha="right",
        va="top",
        bbox=dict(boxstyle="round", facecolor="white", alpha=0.8),
        fontsize=10,
    )

    plt.tight_layout()

    # Save figure
    os.makedirs(save_path, exist_ok=True)
    output_path = Path(save_path) / "class_distribution.png"
    plt.savefig(output_path, dpi=300, bbox_inches="tight")
    print(f"Saved: {output_path}")
    plt.close()


def plot_perclass_kernel_comparison(save_path: str = "static/baseline") -> None:
    """Compare per-class accuracy across kernel sizes (avg pooling, unweighted)."""
    kernel_sizes = [3, 5, 7]

    fig, ax = plt.subplots(figsize=(14, 6))

    colors = {
        3: "#95a5a6",
        5: "#3498db",
        7: "#e74c3c",
    }

    labels_map = {
        3: "k=3",
        5: "k=5",
        7: "k=7",
    }

    # Load confusion matrices and calculate per-class accuracy
    per_class_data = {}
    for k in kernel_sizes:
        model_name = f"SimpleCNN_k{k}_avg_unweighted"
        cm = load_confusion_matrix(model_name)

        num_classes = cm.shape[0]
        acc = []
        for i in range(num_classes):
            total = cm[i].sum()
            if total > 0:
                acc.append(cm[i, i] / total * 100)
            else:
                acc.append(0)
        per_class_data[k] = np.array(acc)

    x = np.arange(num_classes)
    width = 0.25

    # Plot bars for each kernel size
    for idx, k in enumerate(kernel_sizes):
        offset = (idx - 1) * width
        bars = ax.bar(
            x + offset,
            per_class_data[k],
            width,
            label=labels_map[k],
            color=colors[k],
            alpha=0.7,
        )

    ax.set_xlabel("Digit Sum (Class)", fontsize=12, fontweight="bold")
    ax.set_ylabel("Per-Class Accuracy (%)", fontsize=12, fontweight="bold")
    ax.set_title(
        "Per-Class Accuracy: Kernel Size Comparison (Avg Pooling, Unweighted)",
        fontsize=13,
        fontweight="bold",
    )
    ax.set_xticks(x[::3])  # Show every 3rd class label
    ax.set_xticklabels(x[::3])
    ax.legend(fontsize=10)
    ax.grid(axis="y", alpha=0.3)
    ax.set_ylim([0, 105])

    plt.tight_layout()

    # Save figure
    os.makedirs(save_path, exist_ok=True)
    output_path = Path(save_path) / "perclass_kernel_comparison.png"
    plt.savefig(output_path, dpi=300, bbox_inches="tight")
    print(f"Saved: {output_path}")
    plt.close()


